/**
 * Wheel symbols ‚Äî what can appear on the roulette.
 *
 * @typedef {object} SymbolDef
 * @property {string} id
 * @property {string} name
 * @property {string} emoji
 * @property {string} color ‚Äî color group for color bets
 * @property {number} baseValue ‚Äî innate value when landed on
 * @property {'common'|'uncommon'|'rare'|'legendary'} rarity
 * @property {boolean} startsUnlocked
 * @property {string|null} specialEffect
 */

/** @type {SymbolDef[]} */
export const SYMBOLS = [
  // ‚îÄ‚îÄ Commons (starters) ‚îÄ‚îÄ
  { id: 'red',      name: 'Rouge',     emoji: 'üî¥', color: 'red',    baseValue: 10,  rarity: 'common',    startsUnlocked: true,  specialEffect: null },
  { id: 'blue',     name: 'Bleu',      emoji: 'üîµ', color: 'blue',   baseValue: 10,  rarity: 'common',    startsUnlocked: true,  specialEffect: null },

  // ‚îÄ‚îÄ Uncommons ‚îÄ‚îÄ
  { id: 'cherry',   name: 'Cerise',    emoji: 'üçí', color: 'red',    baseValue: 20,  rarity: 'uncommon',  startsUnlocked: false, specialEffect: 'double_payout' },

  // ‚îÄ‚îÄ Legendaries ‚îÄ‚îÄ
  { id: 'void',     name: 'Void',      emoji: 'üåÄ', color: 'void',   baseValue: 0,   rarity: 'legendary', startsUnlocked: false, specialEffect: 'void_burst' },
];

export const SYMBOL_MAP = new Map(SYMBOLS.map(s => [s.id, s]));

export function getSymbol(id) {
  const s = SYMBOL_MAP.get(id);
  if (!s) throw new Error(`Unknown symbol: ${id}`);
  return s;
}

export const RARITY_WEIGHTS = { common: 50, uncommon: 30, rare: 15, legendary: 5 };
